module.exports = "<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no\">\n<title>Her</title>\n<link rel=\"icon\" href=\"data:image/svg+xml,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 100 100'><circle cx='50' cy='50' r='45' fill='%236ee7b7'/><text x='50' y='62' text-anchor='middle' font-size='40' font-weight='bold' font-family='sans-serif' fill='%230a0a0a'>H</text></svg>\">\n<style>\n  @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap');\n  *{margin:0;padding:0;box-sizing:border-box;-webkit-tap-highlight-color:transparent}\n  :root{\n    --bg:#0a0a0a;--surface:#151515;--surface2:#1c1c1c;\n    --border:rgba(255,255,255,.06);\n    --text:#e8e8e8;--text2:#888;--text3:#555;\n    --accent:#6ee7b7;--accent-dim:rgba(110,231,183,.1);\n    --her-bg:rgba(110,231,183,.06);--her-border:rgba(110,231,183,.1);\n    --user-bg:rgba(255,255,255,.05);\n    --max-w:680px;--radius:16px;\n  }\n  html,body{height:100%;background:var(--bg)}\n  body{font-family:'Inter',-apple-system,'SF Pro Text',sans-serif;color:var(--text);display:flex;flex-direction:column;overflow:hidden}\n\n  /* === HEADER === */\n  header{\n    padding:14px 20px;background:var(--bg);\n    display:flex;align-items:center;justify-content:center;\n    position:relative;flex-shrink:0;\n    border-bottom:1px solid var(--border);\n    backdrop-filter:blur(20px);-webkit-backdrop-filter:blur(20px);\n  }\n  .hd-name{font-size:15px;font-weight:700;color:#fff;display:flex;align-items:center;gap:8px}\n  .hd-dot{width:7px;height:7px;border-radius:50%;background:var(--accent);transition:all .3s}\n  .hd-dot.offline{background:#f87171}\n  .hd-status{font-size:11px;font-weight:500;color:var(--text3);margin-left:2px;transition:all .3s}\n  .hd-status.connected{color:var(--accent)}\n  .hd-actions{position:absolute;right:16px;display:flex;gap:6px}\n  .hd-btn{\n    width:32px;height:32px;border-radius:10px;background:transparent;\n    border:1px solid var(--border);color:var(--text3);cursor:pointer;\n    display:flex;align-items:center;justify-content:center;transition:all .2s;\n  }\n  .hd-btn:hover{background:var(--surface);color:var(--text2);border-color:rgba(255,255,255,.12)}\n  .hd-btn svg{width:15px;height:15px}\n\n  /* Settings Panel */\n  .about-overlay{position:fixed;inset:0;background:rgba(0,0,0,.6);backdrop-filter:blur(4px);z-index:200;display:flex;align-items:center;justify-content:center;opacity:0;pointer-events:none;transition:opacity .25s}\n  .about-overlay.open{opacity:1;pointer-events:all}\n  .about-panel{background:var(--surface);border:1px solid var(--border);border-radius:20px;padding:28px;width:min(520px,92vw);max-height:85vh;overflow-y:auto;overflow-x:hidden;transform:translateY(10px);transition:transform .25s}\n  .about-overlay.open .about-panel{transform:translateY(0)}\n  .about-header{display:flex;align-items:center;justify-content:space-between;margin-bottom:20px}\n  .about-title{font-size:16px;font-weight:600;color:var(--text)}\n  .about-close{background:none;border:none;color:var(--text3);cursor:pointer;padding:4px;border-radius:8px;display:flex;align-items:center;justify-content:center;transition:color .2s}\n  .about-close:hover{color:var(--text)}\n  .about-section{margin-bottom:20px}\n  .about-section-title{font-size:11px;font-weight:600;color:var(--text3);text-transform:uppercase;letter-spacing:.08em;margin-bottom:10px}\n  .about-row{display:flex;align-items:center;justify-content:space-between;padding:10px 12px;background:var(--bg);border-radius:10px;margin-bottom:6px;gap:12px}\n  .about-row-label{font-size:12px;color:var(--text3);flex-shrink:0}\n  .about-row-value{font-size:13px;color:var(--text);font-family:monospace;word-break:break-all;text-align:right}\n  .about-copy-btn{background:rgba(255,255,255,.06);border:1px solid var(--border);color:var(--text2);font-size:11px;padding:3px 10px;border-radius:6px;cursor:pointer;white-space:nowrap;transition:all .2s}\n  .about-copy-btn:hover{background:rgba(255,255,255,.1)}\n  .s-field{margin-bottom:10px}\n  .s-label{font-size:12px;color:var(--text3);margin-bottom:4px;display:block}\n  .s-input{width:100%;padding:10px 12px;background:var(--bg);border:1px solid var(--border);border-radius:10px;color:var(--text);font-size:13px;font-family:'Inter',monospace;outline:none;transition:border-color .2s}\n  .s-input:focus{border-color:rgba(110,231,183,.4)}\n  .s-input::placeholder{color:var(--text3)}\n  .s-select{width:100%;padding:10px 12px;background:var(--bg);border:1px solid var(--border);border-radius:10px;color:var(--text);font-size:13px;outline:none;cursor:pointer;-webkit-appearance:none;appearance:none;background-image:url(\"data:image/svg+xml,%3Csvg width='10' height='6' viewBox='0 0 10 6' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M1 1L5 5L9 1' stroke='%23888' stroke-width='1.5' stroke-linecap='round' stroke-linejoin='round'/%3E%3C/svg%3E\");background-repeat:no-repeat;background-position:right 12px center}\n  .s-save-btn{width:100%;padding:12px;border-radius:12px;border:none;background:var(--accent);color:#0a0a0a;font-size:14px;font-weight:600;cursor:pointer;transition:opacity .2s;font-family:'Inter',sans-serif}\n  .s-save-btn:hover{opacity:.9}\n  .s-save-btn:active{transform:scale(.98)}\n  .s-status{font-size:12px;text-align:center;margin-top:8px;color:var(--accent);opacity:0;transition:opacity .3s}\n  .s-status.show{opacity:1}\n  .usage-display{\n    font-size:11px;color:var(--text3);font-variant-numeric:tabular-nums;\n    display:none;\n  }\n  .usage-display.visible{display:inline}\n\n  /* === MESSAGES === */\n  #messages{\n    flex:1;overflow-y:auto;overflow-x:hidden;\n    padding:16px 16px 24px;\n    scroll-behavior:smooth;\n    overscroll-behavior:contain;\n    -webkit-overflow-scrolling:touch;\n  }\n  .msg-list{max-width:var(--max-w);margin:0 auto;display:flex;flex-direction:column;gap:4px}\n\n  /* === WELCOME === */\n  .welcome{\n    display:flex;flex-direction:column;align-items:center;justify-content:center;\n    min-height:60vh;text-align:center;padding:40px 20px;\n  }\n  .welcome-icon{\n    width:64px;height:64px;border-radius:50%;\n    background:var(--accent);\n    display:flex;align-items:center;justify-content:center;\n    margin-bottom:24px;\n  }\n  .welcome-icon svg{width:30px;height:30px;color:#fff}\n  .welcome h2{font-size:24px;font-weight:700;color:#fff;margin-bottom:8px}\n  .welcome p{font-size:14px;color:var(--text2);line-height:1.6;max-width:340px}\n  .welcome-chips{display:flex;flex-wrap:wrap;gap:8px;justify-content:center;margin-top:24px}\n  .chip{\n    padding:8px 16px;border-radius:20px;\n    background:var(--surface);border:1px solid var(--border);\n    font-size:13px;font-weight:500;color:var(--text2);\n    cursor:pointer;transition:all .2s;\n  }\n  .chip:hover{border-color:var(--accent);color:var(--accent);background:var(--accent-dim)}\n\n  /* === MESSAGE BUBBLES === */\n  .msg{\n    padding:2px 0;animation:msgIn .25s ease-out;\n    max-width:var(--max-w);margin:0 auto;width:100%;\n  }\n  @keyframes msgIn{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:none}}\n\n  .msg-user{display:flex;justify-content:flex-end;padding:2px 0}\n  .msg-user .bubble{\n    background:var(--user-bg);border:1px solid var(--border);\n    border-radius:var(--radius) var(--radius) 4px var(--radius);\n    padding:10px 16px;max-width:85%;\n    font-size:15px;line-height:1.6;color:var(--text);word-break:break-word;\n  }\n\n  .msg-her{padding:6px 0}\n  .msg-her .bubble{\n    padding:2px 4px;max-width:100%;\n    font-size:15px;line-height:1.75;color:var(--text);word-break:break-word;\n  }\n  .msg-her .her-label{\n    font-size:12px;font-weight:600;color:var(--accent);\n    margin-bottom:4px;display:flex;align-items:center;gap:5px;\n  }\n  .msg-her .her-label svg{width:12px;height:12px}\n\n  /* === MARKDOWN === */\n  .md h1{font-size:20px;font-weight:700;color:#fff;margin:12px 0 6px}\n  .md h2{font-size:17px;font-weight:700;color:#fff;margin:10px 0 5px}\n  .md h3{font-size:15px;font-weight:700;color:#fff;margin:8px 0 4px}\n  .md h1:first-child,.md h2:first-child,.md h3:first-child{margin-top:0}\n  .md p{margin:4px 0}\n  .md strong{font-weight:600;color:#fff}\n  .md em{color:var(--text2)}\n  .md code{\n    background:rgba(110,231,183,.08);padding:2px 6px;border-radius:4px;\n    font-family:'SF Mono','Fira Code',monospace;font-size:13px;color:var(--accent);\n  }\n  .md pre{\n    background:var(--surface);border:1px solid var(--border);border-radius:10px;\n    padding:12px 16px;margin:8px 0;overflow-x:auto;\n    font-family:'SF Mono','Fira Code',monospace;font-size:13px;line-height:1.55;color:var(--text2);\n  }\n  .md pre code{background:none;padding:0;color:inherit;font-size:inherit}\n  .md ul,.md ol{margin:4px 0;padding-left:20px}\n  .md li{margin:2px 0}\n  .md li::marker{color:var(--accent)}\n  .md blockquote{border-left:3px solid var(--accent);padding:3px 12px;margin:6px 0;color:var(--text2);border-radius:0 6px 6px 0}\n  .md hr{border:none;border-top:1px solid var(--border);margin:12px 0}\n  .md a{color:var(--accent);text-decoration:none}\n  .md a:hover{text-decoration:underline}\n  .md table{width:100%;border-collapse:collapse;margin:8px 0;font-size:14px;border:1px solid var(--border);border-radius:8px;overflow:hidden}\n  .md thead{background:rgba(255,255,255,.03)}\n  .md th{padding:7px 11px;text-align:left;font-weight:600;color:#fff;border-bottom:1px solid var(--border)}\n  .md td{padding:6px 11px;border-bottom:1px solid var(--border)}\n  .md tbody tr:last-child td{border-bottom:none}\n\n  /* === TYPING CURSOR === */\n  .typing-cursor::after{\n    content:'';display:inline-block;width:2px;height:16px;\n    background:var(--accent);margin-left:2px;vertical-align:text-bottom;\n    animation:blink .6s infinite;\n  }\n  @keyframes blink{0%,100%{opacity:1}50%{opacity:0}}\n\n  /* === THINKING === */\n  .thinking{display:flex;align-items:center;gap:4px;padding:8px 4px}\n  .thinking span{\n    width:6px;height:6px;border-radius:50%;background:var(--accent);\n    animation:pulse 1.4s infinite both;opacity:.3;\n  }\n  .thinking span:nth-child(2){animation-delay:.2s}\n  .thinking span:nth-child(3){animation-delay:.4s}\n  @keyframes pulse{0%,80%,100%{opacity:.15}40%{opacity:.7}}\n\n  /* === CMD BLOCK === */\n  .cmd-block{\n    margin:6px 0;background:var(--surface);border:1px solid var(--border);\n    border-radius:10px;overflow:hidden;\n  }\n  .cmd-bar{\n    padding:8px 12px;display:flex;align-items:center;gap:8px;\n    cursor:pointer;transition:background .1s;\n    font-family:'Inter',sans-serif;\n  }\n  .cmd-bar:hover{background:rgba(255,255,255,.02)}\n  .cmd-spinner{\n    width:14px;height:14px;border:2px solid var(--border);\n    border-top-color:var(--accent);border-radius:50%;\n    animation:spin .8s linear infinite;flex-shrink:0;\n  }\n  @keyframes spin{to{transform:rotate(360deg)}}\n  .cmd-bar .cmd-icon{width:14px;height:14px;color:var(--accent);flex-shrink:0}\n  .cmd-bar .cmd-icon.done{color:var(--accent)}\n  .cmd-bar .cmd-icon.fail{color:var(--red)}\n  .cmd-label{font-size:12px;font-weight:500;color:var(--text2);flex:1;min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}\n  .cmd-bar .cmd-toggle{\n    font-size:10px;color:var(--text3);flex-shrink:0;\n    transition:transform .15s;\n  }\n  .cmd-bar .cmd-toggle.open{transform:rotate(180deg)}\n  .cmd-detail{\n    display:none;border-top:1px solid var(--border);\n    font-family:'SF Mono','Fira Code',monospace;font-size:12px;\n  }\n  .cmd-detail.open{display:block}\n  .cmd-detail-cmd{padding:8px 12px;color:var(--accent);white-space:pre-wrap;word-break:break-all;line-height:1.5}\n  .cmd-detail-out{padding:8px 12px;color:var(--text2);border-top:1px solid var(--border);white-space:pre-wrap;word-break:break-all;line-height:1.5;max-height:200px;overflow-y:auto}\n\n  /* === FILE CARD === */\n  /* Progress bar */\n  .progress-bar{\n    margin:8px 0;background:var(--surface);border:1px solid var(--border);\n    border-radius:10px;overflow:hidden;max-width:340px;position:relative;height:28px;\n  }\n  .progress-fill{\n    height:100%;background:linear-gradient(90deg,var(--accent-dim),rgba(110,231,183,.25));\n    border-radius:10px;transition:width .3s ease;width:0%;\n  }\n  .progress-text{\n    position:absolute;inset:0;display:flex;align-items:center;justify-content:center;\n    font-size:11px;font-weight:600;color:var(--accent);\n  }\n  .file-card{\n    margin:8px 0;background:var(--surface);border:1px solid var(--border);\n    border-radius:12px;overflow:hidden;max-width:340px;transition:border-color .2s;\n  }\n  .file-card:hover{border-color:rgba(255,255,255,.1)}\n  .file-card video,.file-card img.file-preview{width:100%;max-height:240px;object-fit:contain;background:#000;display:block}\n  .file-card audio{width:100%;display:block;padding:12px}\n  .file-bar{padding:10px 12px;display:flex;align-items:center;gap:10px}\n  .file-icon{\n    width:36px;height:36px;border-radius:8px;background:var(--accent-dim);\n    display:flex;align-items:center;justify-content:center;flex-shrink:0;\n  }\n  .file-icon svg{width:16px;height:16px;color:var(--accent)}\n  .file-meta{flex:1;min-width:0}\n  .file-name{font-size:13px;font-weight:600;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis}\n  .file-size{font-size:11px;color:var(--text3);margin-top:1px}\n  .file-dl{\n    width:32px;height:32px;border-radius:8px;\n    background:rgba(255,255,255,.04);border:1px solid var(--border);\n    color:var(--text2);cursor:pointer;flex-shrink:0;\n    display:flex;align-items:center;justify-content:center;text-decoration:none;\n    transition:all .15s;\n  }\n  .file-dl:hover{background:rgba(255,255,255,.08);color:var(--text)}\n  .file-dl svg{width:14px;height:14px}\n\n  /* === USER IMAGE === */\n  .msg-img{max-width:280px;border-radius:12px;margin:4px 0;display:block;cursor:zoom-in}\n\n  /* === COMPACTION === */\n  .compaction{\n    display:flex;align-items:center;gap:8px;\n    max-width:var(--max-w);margin:12px auto;\n  }\n  .compaction::before,.compaction::after{content:\"\";flex:1;height:1px;background:linear-gradient(90deg,transparent,var(--accent),transparent);opacity:.2}\n  .compaction-tag{\n    padding:4px 12px;border-radius:20px;\n    background:var(--accent-dim);border:1px solid var(--her-border);\n    font-size:11px;font-weight:500;color:var(--accent);white-space:nowrap;\n  }\n\n  /* === SCHEDULE === */\n  .schedule-hdr{display:flex;align-items:center;gap:6px;font-size:13px;font-weight:600;color:var(--accent);margin-bottom:6px}\n  .schedule-hdr svg{width:14px;height:14px}\n\n  /* === INPUT === */\n  #input-area{padding:8px 16px 16px;background:var(--bg);flex-shrink:0;position:relative}\n  .input-box{\n    max-width:var(--max-w);margin:0 auto;\n    background:var(--surface);border:1px solid var(--border);\n    border-radius:22px;transition:border-color .3s, box-shadow .3s;\n  }\n  .input-box:hover{\n    border-color:rgba(110,231,183,.2);\n    box-shadow:0 0 8px rgba(110,231,183,.08), 0 0 16px rgba(110,231,183,.04);\n  }\n  .input-box:focus-within{\n    border-color:rgba(110,231,183,.3);\n    box-shadow:0 0 10px rgba(110,231,183,.12), 0 0 24px rgba(110,231,183,.06), 0 0 48px rgba(110,231,183,.03);\n  }\n  #img-previews{display:flex;gap:8px;flex-wrap:wrap;padding:10px 12px 0}\n  #img-previews:empty{display:none}\n  .img-preview-item{\n    position:relative;width:64px;height:64px;\n    border-radius:8px;overflow:hidden;flex-shrink:0;border:1px solid var(--border);\n  }\n  .img-preview-item img{width:100%;height:100%;object-fit:cover;display:block}\n  .img-preview-remove{\n    position:absolute;top:2px;right:2px;width:18px;height:18px;border-radius:50%;\n    background:rgba(0,0,0,.75);color:#fff;border:none;cursor:pointer;\n    display:flex;align-items:center;justify-content:center;font-size:10px;\n  }\n  .input-row{display:flex;align-items:center;padding:4px 6px 4px 10px;gap:2px}\n  #input{\n    flex:1;background:transparent;border:none;padding:10px 8px;color:var(--text);\n    font-size:15px;font-family:'Inter',sans-serif;resize:none;outline:none;\n    min-height:42px;max-height:160px;line-height:1.55;\n  }\n  #input::placeholder{color:var(--text3);font-size:13px}\n  .input-btn{\n    width:36px;height:36px;border-radius:50%;border:none;\n    background:transparent;color:var(--text3);cursor:pointer;flex-shrink:0;\n    display:flex;align-items:center;justify-content:center;transition:all .15s;\n  }\n  .input-btn:hover{background:rgba(255,255,255,.05);color:var(--text2)}\n  .input-btn svg{width:18px;height:18px}\n  #send{\n    width:36px;height:36px;border-radius:50%;border:none;\n    background:var(--text3);color:var(--bg);cursor:pointer;flex-shrink:0;\n    display:flex;align-items:center;justify-content:center;\n    transition:all .2s;\n  }\n  #send.active{background:var(--accent)}\n  #send:active{transform:scale(.9)}\n  .input-btn.recording{color:var(--accent);animation:mic-pulse 1s infinite}\n  .input-btn.recording svg{color:#f87171}\n  @keyframes mic-pulse{0%,100%{opacity:1}50%{opacity:.4}}\n  #send:disabled{opacity:.3;cursor:not-allowed;transform:none}\n  #send svg{width:15px;height:15px}\n  #send.stop{background:var(--accent);opacity:1;cursor:pointer}\n  #send.stop svg{width:12px;height:12px}\n  body.light #send.stop{background:var(--accent);color:#fff}\n  .input-hint{max-width:var(--max-w);margin:6px auto 0;font-size:11px;color:var(--text3);display:flex;justify-content:space-between;padding:0 4px}\n\n  /* === SLASH MENU === */\n  .slash-menu{\n    display:none;position:absolute;bottom:100%;left:0;right:0;\n    max-width:var(--max-w);margin:0 auto 8px;\n    background:var(--surface);border:1px solid var(--border);\n    border-radius:14px;padding:6px;z-index:200;\n    animation:slashIn .15s ease-out;\n  }\n  .slash-menu.open{display:block}\n  @keyframes slashIn{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:none}}\n  .slash-item{\n    display:flex;align-items:center;gap:12px;\n    padding:10px 14px;border-radius:10px;cursor:pointer;transition:background .1s;\n  }\n  .slash-item:hover,.slash-item.active{background:rgba(255,255,255,.06)}\n  .slash-item svg{width:18px;height:18px;color:var(--text2);flex-shrink:0}\n  .slash-info{flex:1;min-width:0}\n  .slash-label{font-size:14px;font-weight:600;color:#fff}\n  .slash-desc{font-size:12px;color:var(--text3);margin-top:1px}\n  .slash-status{width:7px;height:7px;border-radius:50%;background:var(--text3);flex-shrink:0}\n  .slash-status.online{background:var(--accent)}\n  .slash-target-badge{\n    display:inline-flex;align-items:center;gap:4px;\n    padding:2px 8px;border-radius:6px;margin-right:4px;\n    background:var(--accent-dim);border:1px solid rgba(110,231,183,.15);\n    font-size:11px;font-weight:600;color:var(--accent);vertical-align:middle;\n  }\n  .slash-target-badge svg{width:12px;height:12px}\n  .slash-target-badge .remove{cursor:pointer;margin-left:2px;opacity:.6}\n  .slash-target-badge .remove:hover{opacity:1}\n\n  /* === TOAST === */\n  .toast{\n    position:fixed;top:16px;left:50%;transform:translateX(-50%) translateY(-80px);\n    background:var(--surface2);color:var(--text);padding:8px 16px;border-radius:12px;\n    font-size:13px;font-weight:500;border:1px solid var(--border);z-index:300;\n    display:flex;align-items:center;gap:6px;transition:transform .3s cubic-bezier(.32,0,.15,1);\n    box-shadow:0 8px 32px rgba(0,0,0,.5);\n  }\n  .toast.show{transform:translateX(-50%) translateY(0)}\n  .toast svg{width:14px;height:14px;color:var(--accent)}\n\n  /* === LIGHTBOX === */\n  .lightbox{display:none;position:fixed;inset:0;background:rgba(0,0,0,.92);z-index:1000;align-items:center;justify-content:center;cursor:zoom-out}\n  .lightbox.open{display:flex}\n  .lightbox img{max-width:92vw;max-height:92vh;border-radius:8px;object-fit:contain}\n\n  /* === SCROLLBAR === */\n  ::-webkit-scrollbar{width:4px}\n  ::-webkit-scrollbar-track{background:transparent}\n  ::-webkit-scrollbar-thumb{background:rgba(255,255,255,.05);border-radius:2px}\n  ::-webkit-scrollbar-thumb:hover{background:rgba(255,255,255,.1)}\n\n  /* === LIGHT MODE === */\n  body.light{\n    --bg:#fafafa;--surface:#fff;--surface2:#fff;\n    --border:rgba(0,0,0,.08);\n    --text:#1a1a1a;--text2:#666;--text3:#aaa;\n    --accent:#059669;--accent-dim:rgba(5,150,105,.06);\n    --her-bg:rgba(5,150,105,.04);--her-border:rgba(5,150,105,.1);\n    --user-bg:rgba(0,0,0,.03);\n  }\n  body.light .md strong,body.light .md h1,body.light .md h2,body.light .md h3{color:#1a1a1a}\n  body.light .md pre{background:#f5f5f5}\n  body.light .cmd-block{background:#f8f8f8}\n  body.light .cmd-body{color:#059669}\n  body.light #send{background:#059669;color:#fff}\n  body.light #send.active{background:#047857}\n  body.light .hd-name{color:#1a1a1a}\n</style>\n</head>\n<body>\n\n<svg xmlns=\"http://www.w3.org/2000/svg\" style=\"display:none\">\n  <symbol id=\"i-bot\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <path d=\"M12 8V4H8\"/><rect width=\"16\" height=\"12\" x=\"4\" y=\"8\" rx=\"2\"/>\n    <path d=\"M2 14h2\"/><path d=\"M20 14h2\"/><path d=\"M15 13v2\"/><path d=\"M9 13v2\"/>\n  </symbol>\n  <symbol id=\"i-send\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <path d=\"M12 19V5\"/><path d=\"m5 12 7-7 7 7\"/>\n  </symbol>\n  <symbol id=\"i-terminal\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <polyline points=\"4 17 10 11 4 5\"/><line x1=\"12\" x2=\"20\" y1=\"19\" y2=\"19\"/>\n  </symbol>\n  <symbol id=\"i-download\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <path d=\"M12 15V3\"/><path d=\"m8 11 4 4 4-4\"/><path d=\"M3 17v3a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-3\"/>\n  </symbol>\n  <symbol id=\"i-file\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <path d=\"M15 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V7Z\"/><path d=\"M14 2v4a2 2 0 0 0 2 2h4\"/>\n  </symbol>\n  <symbol id=\"i-video\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <path d=\"m16 13 5.223 3.482a.5.5 0 0 0 .777-.416V7.934a.5.5 0 0 0-.777-.416L16 11\"/><rect x=\"2\" y=\"6\" width=\"14\" height=\"12\" rx=\"2\"/>\n  </symbol>\n  <symbol id=\"i-image\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <rect width=\"18\" height=\"18\" x=\"3\" y=\"3\" rx=\"2\" ry=\"2\"/><circle cx=\"9\" cy=\"9\" r=\"2\"/>\n    <path d=\"m21 15-3.086-3.086a2 2 0 0 0-2.828 0L6 21\"/>\n  </symbol>\n  <symbol id=\"i-music\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <path d=\"M9 18V5l12-2v13\"/><circle cx=\"6\" cy=\"18\" r=\"3\"/><circle cx=\"18\" cy=\"16\" r=\"3\"/>\n  </symbol>\n  <symbol id=\"i-check\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <circle cx=\"12\" cy=\"12\" r=\"10\"/><path d=\"m9 12 2 2 4-4\"/>\n  </symbol>\n  <symbol id=\"i-plus\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <path d=\"M12 5v14\"/><path d=\"M5 12h14\"/>\n  </symbol>\n  <symbol id=\"i-sun\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <circle cx=\"12\" cy=\"12\" r=\"4\"/><path d=\"M12 2v2\"/><path d=\"M12 20v2\"/><path d=\"m4.93 4.93 1.41 1.41\"/><path d=\"m17.66 17.66 1.41 1.41\"/><path d=\"M2 12h2\"/><path d=\"M20 12h2\"/><path d=\"m6.34 17.66-1.41 1.41\"/><path d=\"m19.07 4.93-1.41 1.41\"/>\n  </symbol>\n  <symbol id=\"i-moon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <path d=\"M12 3a6 6 0 0 0 9 9 9 9 0 1 1-9-9Z\"/>\n  </symbol>\n  <symbol id=\"i-stop\" viewBox=\"0 0 24 24\" fill=\"currentColor\" stroke=\"none\">\n    <rect x=\"6\" y=\"6\" width=\"12\" height=\"12\" rx=\"2\"/>\n  </symbol>\n  <symbol id=\"i-mic\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <path d=\"M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z\"/><path d=\"M19 10v2a7 7 0 0 1-14 0v-2\"/><line x1=\"12\" x2=\"12\" y1=\"19\" y2=\"22\"/>\n  </symbol>\n  <symbol id=\"i-clock\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <circle cx=\"12\" cy=\"12\" r=\"10\"/><polyline points=\"12 6 12 12 16 14\"/>\n  </symbol>\n  <symbol id=\"i-layers\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <path d=\"m12.83 2.18a2 2 0 0 0-1.66 0L2.6 6.08a1 1 0 0 0 0 1.83l8.58 3.91a2 2 0 0 0 1.66 0l8.58-3.9a1 1 0 0 0 0-1.83Z\"/>\n    <path d=\"m22 17.65-9.17 4.16a2 2 0 0 1-1.66 0L2 17.65\"/><path d=\"m22 12.65-9.17 4.16a2 2 0 0 1-1.66 0L2 12.65\"/>\n  </symbol>\n  <symbol id=\"i-monitor\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <rect x=\"2\" y=\"3\" width=\"20\" height=\"14\" rx=\"2\"/><path d=\"M8 21h8\"/><path d=\"M12 17v4\"/>\n  </symbol>\n  <symbol id=\"i-server\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <rect width=\"20\" height=\"8\" x=\"2\" y=\"2\" rx=\"2\"/><rect width=\"20\" height=\"8\" x=\"2\" y=\"14\" rx=\"2\"/>\n    <path d=\"M6 6h.01\"/><path d=\"M6 18h.01\"/>\n  </symbol>\n  <symbol id=\"i-trash\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\n    <path d=\"M3 6h18\"/><path d=\"M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6\"/><path d=\"M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2\"/>\n  </symbol>\n</svg>\n\n<header>\n  <div class=\"hd-name\">Her <span class=\"hd-dot\" id=\"statusDot\"></span><span class=\"hd-status\" id=\"statusText\"></span></div>\n  <div class=\"hd-actions\">\n    <button class=\"hd-btn\" id=\"aboutBtn\" title=\"关于 Her / 部署信息\">\n      <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><circle cx=\"12\" cy=\"12\" r=\"10\"/><line x1=\"12\" y1=\"16\" x2=\"12\" y2=\"12\"/><line x1=\"12\" y1=\"8\" x2=\"12.01\" y2=\"8\"/></svg>\n    </button>\n    <button class=\"hd-btn\" id=\"themeBtn\" title=\"切换主题\">\n      <svg class=\"icon-sun\" style=\"display:none\"><use href=\"#i-sun\"/></svg>\n      <svg class=\"icon-moon\"><use href=\"#i-moon\"/></svg>\n    </button>\n  </div>\n</header>\n\n<!-- Settings Panel -->\n<div class=\"about-overlay\" id=\"aboutOverlay\">\n  <div class=\"about-panel\">\n    <div class=\"about-header\">\n      <div class=\"about-title\">Settings</div>\n      <button class=\"about-close\" id=\"aboutClose\">\n        <svg width=\"16\" height=\"16\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><line x1=\"18\" y1=\"6\" x2=\"6\" y2=\"18\"/><line x1=\"6\" y1=\"6\" x2=\"18\" y2=\"18\"/></svg>\n      </button>\n    </div>\n\n    <div class=\"about-section\">\n      <div class=\"about-section-title\">API Settings</div>\n      <div class=\"s-field\">\n        <label class=\"s-label\">API Key</label>\n        <input class=\"s-input\" type=\"password\" id=\"s-api-key\" placeholder=\"sk-...\">\n        <div style=\"font-size:11px;color:var(--text3);margin-top:6px;line-height:1.8\">\n          <a href=\"https://openrouter.ai/keys\" target=\"_blank\" style=\"color:var(--accent);text-decoration:none\">openrouter.ai</a> 获取 API Key\n        </div>\n      </div>\n      <div class=\"s-field\">\n        <label class=\"s-label\">Base URL</label>\n        <input class=\"s-input\" type=\"text\" id=\"s-base-url\" placeholder=\"https://openrouter.ai/api/v1\">\n      </div>\n      <div class=\"s-field\">\n        <label class=\"s-label\">Default Model</label>\n        <select class=\"s-input\" id=\"s-model\">\n          <optgroup label=\"Anthropic\">\n            <option value=\"anthropic/claude-sonnet-4.6\">Claude Sonnet 4.6</option>\n            <option value=\"anthropic/claude-opus-4.6\">Claude Opus 4.6</option>\n            <option value=\"anthropic/claude-opus-4.5\">Claude Opus 4.5</option>\n          </optgroup>\n          <optgroup label=\"Google\">\n            <option value=\"google/gemini-3.1-pro-preview\">Gemini 3.1 Pro</option>\n            <option value=\"google/gemini-3.1-flash-lite-preview\">Gemini 3.1 Flash Lite</option>\n            <option value=\"google/gemini-3.1-flash-image-preview\">Gemini 3.1 Image</option>\n          </optgroup>\n          <optgroup label=\"OpenAI\">\n            <option value=\"openai/gpt-5\">GPT-5</option>\n            <option value=\"openai/gpt-5-mini\">GPT-5 Mini</option>\n            <option value=\"openai/gpt-5.4-nano\">GPT-5.4 Nano</option>\n          </optgroup>\n          <optgroup label=\"DeepSeek\">\n            <option value=\"deepseek/deepseek-r1\">DeepSeek R1</option>\n            <option value=\"deepseek/deepseek-v3-0324\">DeepSeek V3</option>\n          </optgroup>\n          <optgroup label=\"其他\">\n            <option value=\"xiaomi/mimo-v2-pro\">MiMo V2 Pro</option>\n            <option value=\"minimax/minimax-m2.7\">MiniMax M2.7</option>\n          </optgroup>\n        </select>\n      </div>\n    </div>\n\n    <button class=\"s-save-btn\" id=\"s-save\">保存设置</button>\n    <div class=\"s-status\" id=\"s-status\">已保存</div>\n\n    <div class=\"about-section\" style=\"margin-top:20px\">\n      <div class=\"about-section-title\">WeChat</div>\n      <div id=\"wx-area\">\n        <div id=\"wx-disconnected\">\n          <button class=\"s-save-btn\" id=\"wx-login-btn\" style=\"background:rgba(110,231,183,.15);color:var(--accent)\">扫码登录微信</button>\n        </div>\n        <div id=\"wx-qr\" style=\"display:none;text-align:center\">\n          <p style=\"font-size:12px;color:var(--text3);margin-bottom:10px\">用微信扫描二维码</p>\n          <img id=\"wx-qr-img\" src=\"\" style=\"width:200px;height:200px;border-radius:12px;background:white;padding:8px\">\n        </div>\n        <div id=\"wx-connected\" style=\"display:none\">\n          <div class=\"about-row\">\n            <span class=\"about-row-label\">状态</span>\n            <span class=\"about-row-value\" style=\"color:var(--accent)\" id=\"wx-status-text\">已连接</span>\n          </div>\n          <button class=\"s-save-btn\" id=\"wx-disconnect-btn\" style=\"background:rgba(248,113,113,.15);color:#f87171;margin-top:8px\">断开微信</button>\n        </div>\n      </div>\n    </div>\n  </div>\n</div>\n\n<div id=\"messages\">\n  <div class=\"msg-list\" id=\"msgList\">\n    <div class=\"welcome\" id=\"welcome\">\n      <div class=\"welcome-icon\"><svg><use href=\"#i-bot\"/></svg></div>\n      <h2>Hey, I'm Her</h2>\n      <p>你的 AI 伙伴 — 聊天、写代码、搜索、下载，什么都能帮。</p>\n      <div class=\"welcome-chips\">\n        <div class=\"chip\" data-msg=\"你好呀，介绍下你自己\">聊聊天</div>\n        <div class=\"chip\" data-msg=\"帮我截图 https://example.com\">网页截图</div>\n        <div class=\"chip\" data-msg=\"搜索一下最近的科技新闻\">搜索</div>\n        <div class=\"chip\" data-msg=\"记住我的名字\">记住我</div>\n      </div>\n    </div>\n  </div>\n</div>\n\n<div id=\"input-area\">\n  <div class=\"input-box\" id=\"input-box\">\n    <div id=\"img-previews\"></div>\n    <div class=\"input-row\">\n      <label class=\"input-btn\" title=\"上传文件\" style=\"cursor:pointer\">\n        <svg><use href=\"#i-plus\"/></svg>\n      </label>\n      <input type=\"file\" id=\"file-upload\" hidden accept=\"*/*\">\n      <span id=\"targetBadge\"></span>\n      <textarea id=\"input\" rows=\"1\" placeholder=\"说点什么...\"></textarea>\n      <button class=\"input-btn\" id=\"micBtn\" title=\"语音输入\" style=\"display:none\"><svg><use href=\"#i-mic\"/></svg></button>\n      <button id=\"send\" disabled><svg><use href=\"#i-send\"/></svg></button>\n    </div>\n  </div>\n  <div class=\"input-hint\">\n    <span>输入 / 打开快捷菜单</span>\n    <span style=\"display:flex;align-items:center;gap:8px\">\n      <select id=\"modelSelect\" style=\"background:transparent;border:none;color:var(--text3);font-size:11px;cursor:pointer;outline:none;appearance:none;-webkit-appearance:none;\">\n        <option value=\"\">默认模型</option>\n      </select>\n      <span class=\"usage-display\" id=\"usageDisplay\"></span>\n    </span>\n  </div>\n  <div class=\"slash-menu\" id=\"slashMenu\">\n    <div class=\"slash-item\" data-target=\"clear\" data-prefix=\"/clear\">\n      <svg><use href=\"#i-trash\"/></svg>\n      <div class=\"slash-info\"><div class=\"slash-label\">Clear</div><div class=\"slash-desc\">清空对话</div></div>\n    </div>\n  </div>\n</div>\n<div class=\"toast\" id=\"toast\"></div>\n<div class=\"lightbox\" id=\"lightbox\"><img id=\"lightbox-img\" src=\"\" alt=\"\"></div>\n\n<script>\nconst msgList    = document.getElementById(\"msgList\");\nconst messagesEl = document.getElementById(\"messages\");\nconst welcomeEl  = document.getElementById(\"welcome\");\nconst input      = document.getElementById(\"input\");\nconst sendBtn    = document.getElementById(\"send\");\nconst statusDot  = document.getElementById(\"statusDot\");\nconst imgPreviews= document.getElementById(\"img-previews\");\n\nlet ws, pastedImages = [];\nlet reconnectDelay = 1000;\nlet reconnectAttempts = 0;\nlet wasDisconnected = false;\nlet disconnectTime = null;\nlet isGenerating = false;\nconst statusText = document.getElementById(\"statusText\");\nlet lastClients = [];\n\n// Streaming state\nlet streamBuf = \"\";        // raw markdown accumulator\nlet streamEl = null;       // current <div.md> being streamed into\nlet streamTimer = null;    // throttle timer\nlet streamGroup = null;    // current her message container\nlet thinkingEl = null;\nlet currentCmd = null;\n\nfunction finishCmd(){\n  if(!currentCmd) return;\n  const spinner=currentCmd.querySelector(\".cmd-spinner\");\n  if(spinner) spinner.outerHTML='<svg class=\"cmd-icon done\"><use href=\"#i-check\"/></svg>';\n  const label=currentCmd.querySelector(\".cmd-label\");\n  if(label&&label.textContent.startsWith(\"Running:\")) label.textContent=label.textContent.replace(\"Running:\",\"Done:\");\n  currentCmd=null;\n}\n\nfunction esc(s){const d=document.createElement(\"div\");d.textContent=s;return d.innerHTML}\n\nfunction setGenerating(val){\n  isGenerating=val;\n  if(val){\n    sendBtn.disabled=false;\n    sendBtn.classList.add(\"stop\");\n    sendBtn.classList.remove(\"active\");\n    sendBtn.innerHTML='<svg><use href=\"#i-stop\"/></svg>';\n  }else{\n    sendBtn.classList.remove(\"stop\");\n    sendBtn.innerHTML='<svg><use href=\"#i-send\"/></svg>';\n    updateSendBtn();\n  }\n}\n\nfunction stopGeneration(){\n  if(!isGenerating)return;\n  ws.send(JSON.stringify({type:\"cancel\"}));\n  // Show cancelled state on current cmd block\n  if(currentCmd){\n    const spinner=currentCmd.querySelector(\".cmd-spinner\");\n    if(spinner) spinner.outerHTML='<svg class=\"cmd-icon cancelled\" style=\"color:#f87171\"><use href=\"#i-stop\"/></svg>';\n    const label=currentCmd.querySelector(\".cmd-label\");\n    if(label&&label.textContent.startsWith(\"Running:\")) label.textContent=label.textContent.replace(\"Running:\",\"Cancelled:\");\n    currentCmd=null;\n  }\n  endStream();\n  finalizeHerGroup();\n  setGenerating(false);\n}\n\n// ---- Throttled Markdown Rendering ----\n// Only re-render every 50ms during streaming for smooth performance\nfunction flushStream(){\n  if(!streamEl||!streamBuf) return;\n  streamEl.innerHTML = md(streamBuf);\n  streamEl.classList.add(\"typing-cursor\");\n  scrollDown();\n}\n\nfunction appendStream(text){\n  streamBuf += text;\n  if(!streamTimer) streamTimer = setTimeout(()=>{streamTimer=null;flushStream()}, 50);\n}\n\nfunction endStream(){\n  if(streamTimer){clearTimeout(streamTimer);streamTimer=null}\n  if(streamEl&&streamBuf){\n    streamEl.innerHTML = md(streamBuf);\n    streamEl.classList.remove(\"typing-cursor\");\n  }\n  streamEl=null; streamBuf=\"\"; currentCmd=null;\n  setGenerating(false);\n  scrollDown();\n}\n\n// ---- Markdown ----\nfunction md(raw){\n  let h=esc(raw);\n  h=h.replace(/```(\\w*)\\n([\\s\\S]*?)```/g,(_,l,c)=>`<pre><code>${c.replace(/^\\n|\\n$/g,'')}</code></pre>`);\n  h=h.replace(/`([^`]+)`/g,'<code>$1</code>');\n  h=h.replace(/^### (.+)$/gm,'<h3>$1</h3>');\n  h=h.replace(/^## (.+)$/gm,'<h2>$1</h2>');\n  h=h.replace(/^# (.+)$/gm,'<h1>$1</h1>');\n  h=h.replace(/\\*\\*\\*(.+?)\\*\\*\\*/g,'<strong><em>$1</em></strong>');\n  h=h.replace(/\\*\\*(.+?)\\*\\*/g,'<strong>$1</strong>');\n  h=h.replace(/\\*(.+?)\\*/g,'<em>$1</em>');\n  h=h.replace(/^&gt; (.+)$/gm,'<blockquote>$1</blockquote>');\n  h=h.replace(/^---$/gm,'<hr>');\n  h=h.replace(/((?:^\\|.+\\|$\\n?)+)/gm,block=>{\n    const rows=block.trim().split('\\n');\n    if(rows.length<2||!/^\\|[\\s\\-:|]+\\|$/.test(rows[1]))return block;\n    const p=r=>r.replace(/^\\||\\|$/g,'').split('|').map(c=>c.trim());\n    const ths=p(rows[0]).map(h=>'<th>'+h+'</th>').join('');\n    const body=rows.slice(2).map(r=>'<tr>'+p(r).map(c=>'<td>'+c+'</td>').join('')+'</tr>').join('');\n    return '<table><thead><tr>'+ths+'</tr></thead><tbody>'+body+'</tbody></table>';\n  });\n  h=h.replace(/((?:^\\d+\\. .+$\\n?)+)/gm,block=>'<ol>'+block.trim().split('\\n').map(l=>'<li>'+l.replace(/^\\d+\\.\\s+/,'')+'</li>').join('')+'</ol>');\n  h=h.replace(/((?:^[\\-\\*] .+$\\n?)+)/gm,block=>'<ul>'+block.trim().split('\\n').map(l=>'<li>'+l.replace(/^[\\-\\*]\\s+/,'')+'</li>').join('')+'</ul>');\n  h=h.replace(/\\[([^\\]]+)\\]\\(([^)]+)\\)/g,(_,label,url)=>{\n    if(/^https?:\\/\\//i.test(url))return `<a href=\"${url}\" target=\"_blank\" rel=\"noopener\">${label}</a>`;\n    return `${label} (${url})`;\n  });\n  h=h.replace(/^(?!<[hupbloait]|<\\/|<hr)(.*\\S.*)$/gm,'<p>$1</p>');\n  h=h.replace(/\\n{2,}/g,'\\n');\n  return h;\n}\n\nfunction scrollDown(){messagesEl.scrollTop=messagesEl.scrollHeight}\n\nfunction toast(msg){\n  const t=document.getElementById(\"toast\");\n  t.innerHTML='<svg><use href=\"#i-check\"/></svg>'+esc(msg);\n  t.classList.add(\"show\");\n  setTimeout(()=>t.classList.remove(\"show\"),2200);\n}\n\n// ---- Her message group ----\nfunction getHerGroup(){\n  if(streamGroup) return streamGroup;\n  if(welcomeEl) welcomeEl.style.display=\"none\";\n  const msg=document.createElement(\"div\");\n  msg.className=\"msg msg-her\";\n  const label=document.createElement(\"div\");\n  label.className=\"her-label\";\n  label.innerHTML='<svg><use href=\"#i-bot\"/></svg> Her';\n  const bubble=document.createElement(\"div\");\n  bubble.className=\"bubble\";\n  bubble.appendChild(label);\n  msg.appendChild(bubble);\n  msgList.appendChild(msg);\n  streamGroup=bubble;\n  return bubble;\n}\n\nfunction finalizeHerGroup(){\n  streamGroup=null;\n}\n\nfunction removeThinking(){\n  if(thinkingEl){thinkingEl.remove();thinkingEl=null}\n}\n\n// ---- Paste images ----\nfunction addPastedImage(file){\n  const reader=new FileReader();\n  reader.onload=e=>{\n    const dataUrl=e.target.result;\n    const mediaType=file.type||\"image/png\";\n    const base64=dataUrl.split(',')[1];\n    const id=Date.now()+Math.random();\n    pastedImages.push({id,base64,mediaType,dataUrl});\n    const item=document.createElement(\"div\");\n    item.className=\"img-preview-item\";\n    item.innerHTML=`<img src=\"${dataUrl}\"><button class=\"img-preview-remove\">✕</button>`;\n    item.querySelector(\".img-preview-remove\").onclick=()=>{pastedImages=pastedImages.filter(i=>i.id!=id);item.remove();updateSendBtn()};\n    imgPreviews.appendChild(item);\n    updateSendBtn();\n  };\n  reader.readAsDataURL(file);\n}\n\ndocument.getElementById(\"input-box\").addEventListener(\"paste\",e=>{\n  const items=(e.clipboardData||e.originalEvent.clipboardData).items;\n  let hasImage=false;\n  for(const item of items){\n    if(item.type.startsWith(\"image/\")){hasImage=true;const f=item.getAsFile();if(f)addPastedImage(f)}\n  }\n  if(hasImage)e.preventDefault();\n});\n\n// ---- WebSocket ----\nfunction connect(){\n  const proto=location.protocol===\"https:\"?\"wss:\":\"ws:\";\n  ws=new WebSocket(`${proto}//${location.host}`);\n  ws.onopen=()=>{\n    reconnectDelay=1000;\n    reconnectAttempts=0;\n    statusDot.className=\"hd-dot\";\n    if(wasDisconnected){\n      wasDisconnected=false;\n      // Clean up any pending tool/generation states from before the disconnect\n      finishCmd();\n      setGenerating(false);\n      // Show toast notification\n      toast(\"\\u2705 \\u91cd\\u65b0\\u8fde\\u63a5\\u6210\\u529f\");\n      // Insert a subtle system notice into the chat\n      const _sysMsg=document.createElement(\"div\");\n      _sysMsg.className=\"msg\";\n      _sysMsg.style.cssText=\"justify-content:center;margin:8px 0\";\n      _sysMsg.innerHTML=\"<span style=\\\"font-size:12px;color:var(--text3);background:var(--bg2);padding:4px 14px;border-radius:12px;border:1px solid var(--border)\\\">\\uD83D\\uDD04 \\u670d\\u52a1\\u5668\\u5df2\\u91cd\\u542f\\uff0c\\u53ef\\u4ee5\\u7ee7\\u7bca\\u5bf9\\u8bdd\\u4e86</span>\";\n      msgList.appendChild(_sysMsg);\n      scrollDown();\n    }\n  };\n  ws.onclose=e=>{\n    statusDot.className=\"hd-dot offline\";\n    if(e.code===1008||e.code===4401){window.location.href=\"/login\";return}\n    wasDisconnected=true;\n    disconnectTime=Date.now();\n    // 前5次每1秒重试，之后逐渐退避，最长10秒\n    if(reconnectDelay<=1000) reconnectAttempts=(reconnectAttempts||0)+1;\n    const delay=reconnectAttempts<=5?1000:Math.min(reconnectDelay*1.5,10000);\n    setTimeout(connect, delay);\n    reconnectDelay=delay;\n  };\n  ws.onmessage=e=>handle(JSON.parse(e.data));\n}\n\n// ---- Handle messages ----\nfunction handle(data){\n  if(data.type===\"thinking\"){\n    removeThinking();\n    if(streamEl&&streamBuf){\n      // don't call full endStream here, just flush current stream visually\n      if(streamTimer){clearTimeout(streamTimer);streamTimer=null}\n      streamEl.innerHTML=md(streamBuf);\n      streamEl.classList.remove(\"typing-cursor\");\n      streamEl=null;streamBuf=\"\";\n    }\n    finalizeHerGroup();\n    setGenerating(true);\n    const group=getHerGroup();\n    const dots=document.createElement(\"div\");\n    dots.className=\"thinking\";\n    dots.innerHTML=\"<span></span><span></span><span></span>\";\n    group.appendChild(dots);\n    thinkingEl=dots;\n    scrollDown();\n    return;\n  }\n\n  removeThinking();\n\n  if(data.type===\"stream\"){\n    finishCmd();\n    if(!isGenerating)setGenerating(true);\n    if(!streamEl){\n      const group=getHerGroup();\n      streamEl=document.createElement(\"div\");\n      streamEl.className=\"md\";\n      group.appendChild(streamEl);\n      streamBuf=\"\";\n    }\n    appendStream(data.text);\n\n  }else if(data.type===\"stream_end\"){\n    finishCmd();\n    endStream();\n    finalizeHerGroup();\n\n  }else if(data.type===\"command\"){\n    finishCmd();\n    const group=getHerGroup();\n    const block=document.createElement(\"div\");\n    block.className=\"cmd-block\";\n    // Summarize command for display\n    const cmd=data.command||\"\";\n    const shortCmd=cmd.length>60?cmd.slice(0,60)+\"...\":cmd;\n    block.innerHTML=\n      `<div class=\"cmd-bar\" onclick=\"this.querySelector('.cmd-toggle').classList.toggle('open');this.nextElementSibling.classList.toggle('open')\">\n        <div class=\"cmd-spinner\"></div>\n        <span class=\"cmd-label\">Running: ${esc(shortCmd)}</span>\n        <span class=\"cmd-toggle\">▼</span>\n      </div>\n      <div class=\"cmd-detail\">\n        <div class=\"cmd-detail-cmd\">$ ${esc(cmd)}</div>\n      </div>`;\n    group.appendChild(block);\n    currentCmd=block;\n    scrollDown();\n\n  }else if(data.type===\"command_output\"){\n    if(currentCmd){\n      const output=(data.output||\"\").trim();\n      if(output){\n        const detail=currentCmd.querySelector(\".cmd-detail\");\n        if(detail){\n          const out=document.createElement(\"div\");\n          out.className=\"cmd-detail-out\";\n          out.textContent=output;\n          detail.appendChild(out);\n        }\n      }\n      // Mark as done\n      finishCmd();\n      scrollDown();\n    }\n\n  }else if(data.type===\"file\"){\n    const group=getHerGroup();\n    const card=document.createElement(\"div\");\n    card.className=\"file-card\";\n    let preview=\"\";\n    if(data.fileType===\"video\")preview=`<video controls preload=\"metadata\" src=\"${data.url}\"></video>`;\n    else if(data.fileType===\"image\")preview=`<img class=\"file-preview\" src=\"${data.url}\" alt=\"${esc(data.filename)}\">`;\n    else if(data.fileType===\"audio\")preview=`<audio controls src=\"${data.url}\"></audio>`;\n    const icons={video:\"#i-video\",image:\"#i-image\",audio:\"#i-music\",file:\"#i-file\"};\n    card.innerHTML=`${preview}<div class=\"file-bar\"><div class=\"file-icon\"><svg><use href=\"${icons[data.fileType]||'#i-file'}\"/></svg></div><div class=\"file-meta\"><div class=\"file-name\">${esc(data.filename)}</div><div class=\"file-size\">${data.size}</div></div><a class=\"file-dl\" href=\"${data.url}\" download=\"${esc(data.filename)}\"><svg><use href=\"#i-download\"/></svg></a></div>`;\n    group.appendChild(card);\n    scrollDown();\n\n  }else if(data.type===\"response\"){\n    // fallback for non-streamed responses\n    const group=getHerGroup();\n    const text=document.createElement(\"div\");\n    text.className=\"md\";\n    text.innerHTML=md(data.text);\n    group.appendChild(text);\n    currentCmd=null;setGenerating(false);\n    finalizeHerGroup();\n    scrollDown();\n\n  }else if(data.type===\"progress\"){\n    // Download/task progress bar\n    const group=getHerGroup();\n    let bar=group.querySelector(\".progress-bar\");\n    if(!bar){\n      bar=document.createElement(\"div\");\n      bar.className=\"progress-bar\";\n      bar.innerHTML='<div class=\"progress-fill\"></div><div class=\"progress-text\"></div>';\n      group.appendChild(bar);\n    }\n    const fill=bar.querySelector(\".progress-fill\");\n    const text=bar.querySelector(\".progress-text\");\n    fill.style.width=Math.min(100,data.percent||0)+\"%\";\n    text.textContent=data.detail||`${data.percent}%`;\n    if(data.percent>=100){\n      setTimeout(()=>{try{bar.remove();}catch(_){}},3000);\n    }\n    scrollDown();\n\n  }else if(data.type===\"memory_saved\"){\n    toast(\"已记住: \"+data.key);\n\n  }else if(data.type===\"skill_saved\"){\n    const verb=data.action===\"created\"?\"💡 学会了\":\"🔄 更新了\";\n    const bg=data.background?\" (自动)\":\"\";\n    toast(`${verb}: ${data.name}${bg}`);\n\n  }else if(data.type===\"compaction\"){\n    finalizeHerGroup();\n    const notice=document.createElement(\"div\");\n    notice.className=\"compaction\";\n    notice.innerHTML='<div class=\"compaction-tag\">上下文已压缩</div>';\n    msgList.appendChild(notice);\n    scrollDown();\n\n  }else if(data.type===\"clear\"){\n    finalizeHerGroup();endStream();removeThinking();currentCmd=null;\n    msgList.innerHTML='';\n    document.getElementById(\"usageDisplay\").className=\"usage-display\";\n    const wel=document.createElement(\"div\");\n    wel.className=\"welcome\";wel.id=\"welcome\";\n    wel.innerHTML=`<div class=\"welcome-icon\"><svg><use href=\"#i-bot\"/></svg></div><h2>Hey, I'm Her</h2><p>你的 AI 伙伴 — 聊天、写代码、搜索、下载，什么都能帮。</p><div class=\"welcome-chips\"><div class=\"chip\" data-msg=\"你好呀，介绍下你自己\">聊聊天</div><div class=\"chip\" data-msg=\"帮我截图 https://example.com\">网页截图</div><div class=\"chip\" data-msg=\"搜索一下最近的科技新闻\">搜索</div><div class=\"chip\" data-msg=\"记住我的名字\">记住我</div></div>`;\n    wel.querySelectorAll(\".chip\").forEach(c=>c.addEventListener(\"click\",()=>send(c.dataset.msg)));\n    msgList.appendChild(wel);\n    sendBtn.disabled=true;\n    toast(\"对话已清空\");\n\n  }else if(data.type===\"schedule_result\"){\n    finalizeHerGroup();\n    const group=getHerGroup();\n    const hdr=document.createElement(\"div\");\n    hdr.className=\"schedule-hdr\";\n    hdr.innerHTML='<svg><use href=\"#i-clock\"/></svg> '+esc(data.description);\n    group.appendChild(hdr);\n    if(data.output&&data.output.trim()){\n      const out=document.createElement(\"div\");\n      out.className=\"md\";\n      out.innerHTML=md(data.output.trim());\n      group.appendChild(out);\n    }\n    finalizeHerGroup();\n    scrollDown();\n\n  }else if(data.type===\"client_status\"){\n    return;\n  }else if(data.type===\"weixin_status\"){\n    updateWxUI(data.status, data.qrUrl);\n    if(data.status===\"connected\") toast(\"微信已连接\");\n    return;\n  }else if(data.type===\"weixin_message\"){\n    // Show WeChat messages in chat\n    if(data.replyText){\n      finalizeHerGroup();\n      const group=getHerGroup();\n      const hdr=document.createElement(\"div\");\n      hdr.className=\"schedule-hdr\";\n      hdr.innerHTML='<svg><use href=\"#i-bot\"/></svg> 微信: '+esc(data.from||\"\").slice(0,20);\n      group.appendChild(hdr);\n      const md_el=document.createElement(\"div\");\n      md_el.className=\"md\";\n      md_el.innerHTML=md(data.replyText);\n      group.appendChild(md_el);\n      finalizeHerGroup();\n      scrollDown();\n    }\n    return;\n\n  }else if(data.type===\"browser_exec\"){\n    // AI wants to execute JS in our browser\n    finishCmd();\n    const group=getHerGroup();\n    const block=document.createElement(\"div\");\n    block.className=\"cmd-block\";\n    const desc=data.description||\"Executing in browser...\";\n    block.innerHTML=\n      `<div class=\"cmd-bar\" onclick=\"this.querySelector('.cmd-toggle').classList.toggle('open');this.nextElementSibling.classList.toggle('open')\">\n        <div class=\"cmd-spinner\"></div>\n        <span class=\"cmd-label\">Browser: ${esc(desc)}</span>\n        <span class=\"cmd-toggle\">▼</span>\n      </div>\n      <div class=\"cmd-detail\">\n        <div class=\"cmd-detail-cmd\">${esc(data.code)}</div>\n      </div>`;\n    group.appendChild(block);\n    currentCmd=block;\n    scrollDown();\n    // Execute the code\n    (async()=>{\n      try{\n        const fn=new Function(\"return (async()=>{\"+data.code+\"})()\");\n        const result=await fn();\n        const resultStr=typeof result===\"object\"?JSON.stringify(result):String(result??\"\");\n        ws.send(JSON.stringify({type:\"browser_result\",id:data.id,result:resultStr}));\n        // Mark done\n        if(currentCmd===block){\n          const spinner=block.querySelector(\".cmd-spinner\");\n          if(spinner) spinner.outerHTML='<svg class=\"cmd-icon done\"><use href=\"#i-check\"/></svg>';\n          const label=block.querySelector(\".cmd-label\");\n          if(label) label.textContent=label.textContent.replace(\"Browser:\",\"Done:\");\n          if(resultStr.trim()){\n            const detail=block.querySelector(\".cmd-detail\");\n            if(detail){const out=document.createElement(\"div\");out.className=\"cmd-detail-out\";out.textContent=resultStr.slice(0,2000);detail.appendChild(out)}\n          }\n          if(currentCmd===block) currentCmd=null;\n        }\n      }catch(err){\n        ws.send(JSON.stringify({type:\"browser_error\",id:data.id,error:err.message||String(err)}));\n        if(currentCmd===block){\n          const spinner=block.querySelector(\".cmd-spinner\");\n          if(spinner) spinner.outerHTML='<svg class=\"cmd-icon cancelled\" style=\"color:#f87171\"><use href=\"#i-stop\"/></svg>';\n          const label=block.querySelector(\".cmd-label\");\n          if(label) label.textContent=label.textContent.replace(\"Browser:\",\"Error:\");\n          const detail=block.querySelector(\".cmd-detail\");\n          if(detail){const out=document.createElement(\"div\");out.className=\"cmd-detail-out\";out.style.color=\"#f87171\";out.textContent=err.message||String(err);detail.appendChild(out)}\n          if(currentCmd===block) currentCmd=null;\n        }\n      }\n      scrollDown();\n    })();\n    return;\n\n  }else if(data.type===\"usage\"){\n    // Hidden — no token/cost display\n    return;\n\n  }else if(data.type===\"restore\"){\n    // Restore conversation from server on reconnect\n    if(welcomeEl) welcomeEl.style.display=\"none\";\n    msgList.innerHTML=\"\";\n    for(const msg of data.messages){\n      if(msg.role===\"user\"){\n        const el=document.createElement(\"div\");\n        el.className=\"msg msg-user\";\n        const bubble=document.createElement(\"div\");\n        bubble.className=\"bubble\";\n        if(msg.hasImages){\n          const p=document.createElement(\"div\");\n          p.style.cssText=\"font-size:12px;color:var(--text3);margin-bottom:4px\";\n          p.textContent=\"[图片]\";\n          bubble.appendChild(p);\n        }\n        const p=document.createElement(\"div\");\n        p.textContent=msg.text;\n        bubble.appendChild(p);\n        el.appendChild(bubble);\n        msgList.appendChild(el);\n      }else{\n        const el=document.createElement(\"div\");\n        el.className=\"msg msg-her\";\n        const bubble=document.createElement(\"div\");\n        bubble.className=\"bubble\";\n        const label=document.createElement(\"div\");\n        label.className=\"her-label\";\n        label.innerHTML='<svg><use href=\"#i-bot\"/></svg> Her';\n        bubble.appendChild(label);\n        const content=document.createElement(\"div\");\n        content.className=\"md\";\n        content.innerHTML=md(msg.text);\n        bubble.appendChild(content);\n        el.appendChild(bubble);\n        msgList.appendChild(el);\n      }\n    }\n    scrollDown();\n    return;\n\n  }else if(data.type===\"error\"){\n    const group=getHerGroup();\n    const text=document.createElement(\"div\");\n    text.className=\"md\";\n    text.style.color=\"#f87171\";\n    text.textContent=data.text;\n    group.appendChild(text);\n    setGenerating(false);\n    finalizeHerGroup();\n    scrollDown();\n  }\n}\n\n// ---- Send ----\nfunction updateSendBtn(){\n  const has=input.value.trim().length>0||pastedImages.length>0;\n  sendBtn.disabled=!has;\n  sendBtn.classList.toggle(\"active\",has);\n}\n\nfunction send(text){\n  text=(text||input.value).trim();\n  if(!text&&pastedImages.length===0)return;\n\n  // Get target prefix for AI context\n  var prefix=window.getTargetPrefix?window.getTargetPrefix():\"\";\n  var displayText=text;\n  var aiText=(prefix&&text!==\"/clear\")?prefix+text:text;\n\n  finalizeHerGroup();endStream();\n  if(welcomeEl)welcomeEl.style.display=\"none\";\n\n  // User message bubble (show display text, not prefix)\n  const msg=document.createElement(\"div\");\n  msg.className=\"msg msg-user\";\n  const bubble=document.createElement(\"div\");\n  bubble.className=\"bubble\";\n  pastedImages.forEach(img=>{\n    const el=document.createElement(\"img\");\n    el.src=img.dataUrl;el.className=\"msg-img\";\n    el.onclick=()=>openLightbox(img.dataUrl);\n    bubble.appendChild(el);\n  });\n  if(displayText){\n    const p=document.createElement(\"div\");\n    // Show target badge in bubble if prefix active\n    if(prefix&&displayText!==\"/clear\"){\n      const tgt=prefix.match(/Windows|Mac|服务器/);\n      if(tgt) p.innerHTML='<span class=\"slash-target-badge\" style=\"margin-right:6px\"><svg style=\"width:12px;height:12px\"><use href=\"'+(prefix.includes(\"服务器\")?'#i-server':'#i-monitor')+'\"/></svg>'+tgt[0]+'</span>'+esc(displayText);\n      else p.textContent=displayText;\n    }else{\n      p.textContent=displayText;\n    }\n    bubble.appendChild(p);\n  }\n  msg.appendChild(bubble);\n  msgList.appendChild(msg);\n  scrollDown();\n\n  ws.send(JSON.stringify({\n    message:aiText||\"请分析这张图片\",\n    images:pastedImages.map(i=>({base64:i.base64,mediaType:i.mediaType})),\n    model:document.getElementById(\"modelSelect\").value\n  }));\n\n  input.value=\"\";input.style.height=\"auto\";\n  pastedImages=[];imgPreviews.innerHTML=\"\";\n  sendBtn.disabled=true;sendBtn.classList.remove(\"active\");\n}\n\n// ---- Lightbox ----\nfunction openLightbox(src){\n  document.getElementById(\"lightbox-img\").src=src;\n  document.getElementById(\"lightbox\").classList.add(\"open\");\n}\ndocument.getElementById(\"lightbox\").onclick=()=>document.getElementById(\"lightbox\").classList.remove(\"open\");\n\n// ---- Events ----\nsendBtn.addEventListener(\"click\",()=>{if(isGenerating)stopGeneration();else send()});\ninput.addEventListener(\"keydown\",e=>{\n  if(e.key===\"Enter\"&&!e.shiftKey){\n    // Don't send if slash menu is open\n    const sm=document.getElementById(\"slashMenu\");\n    if(sm&&sm.classList.contains(\"open\")){return;}\n    e.preventDefault();send();\n  }\n});\ninput.addEventListener(\"input\",()=>{\n  input.style.height=\"auto\";\n  input.style.height=Math.min(input.scrollHeight,160)+\"px\";\n  updateSendBtn();\n});\ndocument.querySelectorAll(\".chip\").forEach(c=>c.addEventListener(\"click\",()=>send(c.dataset.msg)));\n\n// ---- File upload ----\nconst fileInput=document.getElementById(\"file-upload\");\ndocument.querySelector(\"label[title='上传文件']\").addEventListener(\"click\",()=>fileInput.click());\nfileInput.addEventListener(\"change\",async()=>{\n  const file=fileInput.files[0];\n  if(!file)return;\n  if(file.type.startsWith(\"image/\")){addPastedImage(file);fileInput.value=\"\";return}\n  const form=new FormData();form.append(\"file\",file);\n  try{\n    const res=await fetch(\"/api/upload\",{method:\"POST\",body:form});\n    const data=await res.json();\n    if(data.error)throw new Error(data.error);\n    const size=file.size<1024*1024?(file.size/1024).toFixed(1)+\"KB\":(file.size/1024/1024).toFixed(1)+\"MB\";\n    toast(\"已上传: \"+data.filename);\n    send(\"我上传了一个文件: \"+data.filename+\"(\"+size+\")，已保存到共享目录。\");\n  }catch(err){toast(\"上传失败: \"+err.message)}\n  fileInput.value=\"\";\n});\n\n// ---- Theme ----\n(function(){\n  const btn=document.getElementById(\"themeBtn\");\n  const sunIcon=btn.querySelector(\".icon-sun\");\n  const moonIcon=btn.querySelector(\".icon-moon\");\n  if(localStorage.getItem(\"her-theme\")===\"light\"){\n    document.body.classList.add(\"light\");\n    sunIcon.style.display=\"block\";moonIcon.style.display=\"none\";\n  }\n  btn.addEventListener(\"click\",()=>{\n    const isLight=document.body.classList.toggle(\"light\");\n    localStorage.setItem(\"her-theme\",isLight?\"light\":\"dark\");\n    sunIcon.style.display=isLight?\"block\":\"none\";\n    moonIcon.style.display=isLight?\"none\":\"block\";\n  });\n})();\n\n// ---- Voice Input ----\n(function(){\n  const SpeechRecognition=window.SpeechRecognition||window.webkitSpeechRecognition;\n  if(!SpeechRecognition)return; // browser doesn't support\n  const micBtn=document.getElementById(\"micBtn\");\n  micBtn.style.display=\"flex\";\n  let recognition=null;\n  let isRecording=false;\n\n  micBtn.addEventListener(\"click\",()=>{\n    if(isRecording){\n      recognition.stop();\n      return;\n    }\n    recognition=new SpeechRecognition();\n    recognition.lang=navigator.language||\"zh-CN\";\n    recognition.interimResults=true;\n    recognition.continuous=true;\n    recognition.maxAlternatives=1;\n\n    let finalTranscript=\"\";\n    const prevValue=input.value;\n\n    recognition.onstart=()=>{\n      isRecording=true;\n      micBtn.classList.add(\"recording\");\n      input.placeholder=\"正在听...\";\n    };\n\n    recognition.onresult=(e)=>{\n      let interim=\"\";\n      for(let i=e.resultIndex;i<e.results.length;i++){\n        if(e.results[i].isFinal){\n          finalTranscript+=e.results[i][0].transcript;\n        }else{\n          interim+=e.results[i][0].transcript;\n        }\n      }\n      input.value=prevValue+(prevValue?\" \":\"\")+finalTranscript+interim;\n      input.style.height=\"auto\";\n      input.style.height=Math.min(input.scrollHeight,160)+\"px\";\n      updateSendBtn();\n    };\n\n    recognition.onend=()=>{\n      isRecording=false;\n      micBtn.classList.remove(\"recording\");\n      input.placeholder=\"说点什么...\";\n      // Apply final transcript\n      if(finalTranscript){\n        input.value=prevValue+(prevValue?\" \":\"\")+finalTranscript;\n        updateSendBtn();\n      }\n      input.focus();\n    };\n\n    recognition.onerror=(e)=>{\n      isRecording=false;\n      micBtn.classList.remove(\"recording\");\n      input.placeholder=\"说点什么...\";\n      if(e.error===\"not-allowed\"){\n        toast(\"需要允许麦克风权限\");\n      }\n    };\n\n    recognition.start();\n  });\n})();\n\n// ---- Slash Menu ----\n(function(){\n  const menu=document.getElementById(\"slashMenu\");\n  const badge=document.getElementById(\"targetBadge\");\n  const items=menu.querySelectorAll(\".slash-item\");\n  let currentTarget=null;\n  let activeIdx=0;\n\n  function showMenu(){\n    activeIdx=0;\n    items.forEach((it,i)=>it.classList.toggle(\"active\",i===0));\n    menu.classList.add(\"open\");\n  }\n  function hideMenu(){\n    menu.classList.remove(\"open\");\n  }\n  function setTarget(target,prefix){\n    if(target===\"clear\"){\n      input.value=\"\";\n      hideMenu();\n      send(\"/clear\");\n      return;\n    }\n    currentTarget=target;\n    badge.innerHTML='<span class=\"slash-target-badge\"><svg><use href=\"'+(target==='server'?'#i-server':'#i-monitor')+'\"/></svg>'+\n      prefix.replace(/[\\[\\] ]/g,'')+'<span class=\"remove\" onclick=\"clearTarget()\">✕</span></span>';\n    input.value=\"\";\n    input.placeholder=\"在 \"+prefix.replace(/[\\[\\] ]/g,'')+\" 上做什么...\";\n    hideMenu();\n    input.focus();\n    updateSendBtn();\n  }\n  window.clearTarget=function(){\n    currentTarget=null;\n    badge.innerHTML=\"\";\n    input.placeholder=\"说点什么...\";\n    updateSendBtn();\n  };\n  // Expose for send function\n  window.getTargetPrefix=function(){\n    if(!currentTarget) return \"\";\n    const prefixes={win:\"[在 Windows 上执行] \",mac:\"[在 Mac 上执行] \",server:\"[在服务器上执行] \"};\n    return prefixes[currentTarget]||\"\";\n  };\n  window.clearTargetAfterSend=function(){\n    // Keep target selected after send so user can chain commands\n  };\n\n  items.forEach((it,i)=>{\n    it.addEventListener(\"click\",()=>{\n      setTarget(it.dataset.target, it.dataset.prefix);\n    });\n    it.addEventListener(\"mouseenter\",()=>{\n      activeIdx=i;\n      items.forEach((x,j)=>x.classList.toggle(\"active\",j===i));\n    });\n  });\n\n  input.addEventListener(\"input\",()=>{\n    const v=input.value;\n    if(v===\"/\"){\n      showMenu();\n    }else if(v.startsWith(\"/\")){\n      const q=v.slice(1).toLowerCase();\n      let anyVisible=false;\n      items.forEach(it=>{\n        const match=it.dataset.target.includes(q)||it.querySelector(\".slash-label\").textContent.toLowerCase().includes(q);\n        it.style.display=match?\"flex\":\"none\";\n        if(match) anyVisible=true;\n      });\n      if(anyVisible) menu.classList.add(\"open\"); else hideMenu();\n    }else{\n      hideMenu();\n    }\n  });\n\n  input.addEventListener(\"keydown\",e=>{\n    if(!menu.classList.contains(\"open\")) return;\n    const visible=[...items].filter(it=>it.style.display!==\"none\");\n    if(e.key===\"ArrowDown\"){\n      e.preventDefault();\n      activeIdx=Math.min(activeIdx+1,visible.length-1);\n      visible.forEach((it,i)=>it.classList.toggle(\"active\",i===activeIdx));\n    }else if(e.key===\"ArrowUp\"){\n      e.preventDefault();\n      activeIdx=Math.max(activeIdx-1,0);\n      visible.forEach((it,i)=>it.classList.toggle(\"active\",i===activeIdx));\n    }else if(e.key===\"Enter\"&&!e.shiftKey){\n      e.preventDefault();\n      const sel=visible[activeIdx];\n      if(sel) setTarget(sel.dataset.target, sel.dataset.prefix);\n    }else if(e.key===\"Escape\"){\n      hideMenu();\n      input.value=\"\";\n      updateSendBtn();\n    }\n  });\n\n  // Close menu on click outside\n  document.addEventListener(\"click\",e=>{\n    if(!menu.contains(e.target)&&e.target!==input) hideMenu();\n  });\n})();\n\nconnect();\n\n// ===== Load Models =====\nasync function loadModels() {\n  try {\n    const res = await fetch(\"/api/models\");\n    const data = await res.json();\n    const select = document.getElementById(\"modelSelect\");\n    select.innerHTML = \"\";\n    const groups = {};\n    for (const m of data.models) {\n      if (!groups[m.group]) groups[m.group] = [];\n      groups[m.group].push(m);\n    }\n    for (const [groupName, items] of Object.entries(groups)) {\n      const optgroup = document.createElement(\"optgroup\");\n      optgroup.label = groupName;\n      for (const m of items) {\n        const opt = document.createElement(\"option\");\n        opt.value = m.id;\n        opt.textContent = m.name;\n        if (m.id === data.defaultModel) opt.selected = true;\n        optgroup.appendChild(opt);\n      }\n      select.appendChild(optgroup);\n    }\n  } catch(e) { console.log(\"Failed to load models:\", e); }\n}\nloadModels();\n\n// ===== Settings Panel =====\nasync function loadSettingsPanel() {\n  try {\n    const res = await fetch(\"/api/settings\");\n    const cfg = await res.json();\n    document.getElementById(\"s-api-key\").value = cfg.apiKey || \"\";\n    document.getElementById(\"s-base-url\").value = cfg.baseUrl || \"\";\n    document.getElementById(\"s-model\").value = cfg.model || \"anthropic/claude-sonnet-4.6\";\n  } catch(e) { console.log(\"Failed to load settings:\", e); }\n}\n\ndocument.getElementById(\"s-save\").addEventListener(\"click\", async () => {\n  const body = {};\n  const key = document.getElementById(\"s-api-key\").value.trim();\n  if (key && !key.startsWith(\"sk-...\")) body.apiKey = key;\n  body.baseUrl = document.getElementById(\"s-base-url\").value.trim();\n  body.model = document.getElementById(\"s-model\").value;\n  try {\n    const res = await fetch(\"/api/settings\", { method: \"POST\", headers: { \"Content-Type\": \"application/json\" }, body: JSON.stringify(body) });\n    if (res.ok) {\n      const st = document.getElementById(\"s-status\");\n      st.textContent = \"已保存\";\n      st.classList.add(\"show\");\n      setTimeout(() => st.classList.remove(\"show\"), 2000);\n      loadModels();\n      loadSettingsPanel();\n    } else {\n      toast(\"保存失败\");\n    }\n  } catch(e) { toast(\"保存失败: \" + e.message); }\n});\n\ndocument.getElementById(\"aboutBtn\").addEventListener(\"click\", () => {\n  document.getElementById(\"aboutOverlay\").classList.add(\"open\");\n  loadSettingsPanel();\n});\n\ndocument.getElementById(\"aboutClose\").addEventListener(\"click\", () => {\n  document.getElementById(\"aboutOverlay\").classList.remove(\"open\");\n});\n\ndocument.getElementById(\"aboutOverlay\").addEventListener(\"click\", (e) => {\n  if (e.target === e.currentTarget) e.currentTarget.classList.remove(\"open\");\n});\n\n// ===== WeChat =====\nfunction updateWxUI(status, qrUrl) {\n  const disc = document.getElementById(\"wx-disconnected\");\n  const qr = document.getElementById(\"wx-qr\");\n  const conn = document.getElementById(\"wx-connected\");\n  disc.style.display = \"none\";\n  qr.style.display = \"none\";\n  conn.style.display = \"none\";\n\n  if (status === \"qr_pending\" && qrUrl) {\n    qr.style.display = \"block\";\n    // qrUrl is a WeChat link, convert to QR image via API\n    document.getElementById(\"wx-qr-img\").src = \"https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=\" + encodeURIComponent(qrUrl);\n  } else if (status === \"qr_scanned\") {\n    qr.style.display = \"block\";\n    document.querySelector(\"#wx-qr p\").textContent = \"已扫码，请在手机上确认...\";\n  } else if (status === \"connected\") {\n    conn.style.display = \"block\";\n  } else {\n    disc.style.display = \"block\";\n  }\n}\n\ndocument.getElementById(\"wx-login-btn\").addEventListener(\"click\", async () => {\n  const btn = document.getElementById(\"wx-login-btn\");\n  btn.disabled = true;\n  btn.textContent = \"连接中...\";\n  try {\n    const res = await fetch(\"/api/weixin/login\", { method: \"POST\" });\n    const data = await res.json();\n    if (!data.success && data.error) {\n      toast(\"微信: \" + data.error);\n      updateWxUI(\"disconnected\");\n    }\n  } catch(e) {\n    toast(\"微信登录失败\");\n    updateWxUI(\"disconnected\");\n  }\n  btn.disabled = false;\n  btn.textContent = \"扫码登录微信\";\n});\n\ndocument.getElementById(\"wx-disconnect-btn\").addEventListener(\"click\", async () => {\n  await fetch(\"/api/weixin/disconnect\", { method: \"POST\" });\n  updateWxUI(\"disconnected\");\n  toast(\"微信已断开\");\n});\n\n// Load initial WeChat status\n(async function() {\n  try {\n    const res = await fetch(\"/api/weixin/status\");\n    const data = await res.json();\n    updateWxUI(data.status);\n  } catch(e) {}\n})();\n\n</script>\n</body>\n</html>\n";
